mapper.select:
	/* com.erns.es.log.mapper.ApiProcLogDAO.getList */

	SELECT B.* FROM (
		SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
			SELECT

			FROM T_API_PROC_H AA



			ORDER BY AA.RGT_DTTM DESC
		) A
	) B

     WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

mapper.insert:
/* com.erns.es.log.mapper.ApiProcLogDAO.insert */
SELECT nextval('seq_t_api_proc_log')
INSERT INTO T_API_PROC_H ( API_LOG_SEQ , MEMB_SEQ , QUERY_STR , PROC_STATUS , PROC_MSG , PROC_TYPE , RGT_DTTM ) VALUES( #{apiLogSeq ,jdbcType=INTEGER} , COALESCE(#{membSeq ,jdbcType=INTEGER}, 0) ,CASE WHEN #{queryStr ,jdbcType=VARCHAR} IS NOT NULL THEN SUBSTRING(#{queryStr ,jdbcType=VARCHAR} FROM 1 FOR 500) ELSE NULL END , #{procStatus ,jdbcType=CHAR} , #{procMsg ,jdbcType=VARCHAR} , COALESCE(#{procType ,jdbcType=VARCHAR}, 'API') , now() )
